  1	import * as React from 'react';
  2	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
  3	import { K8sKind } from '@openshift-console/dynamic-plugin-sdk/lib/api/common-types';
  4	import * as _ from 'lodash-es';
  5	import {
  6	  Button,
  7	  Modal,
  8	  ModalVariant,
  9	  Title,
 10	  TitleSizes,
 11	} from '@patternfly/react-core';
 12	import FormAlertInline from '../generic/FormAlertInline';
 13	import { LoadingInline } from '../generic/Loading';
 14	import { getAnnotations } from '../selectors';
 15	import { K8sResourceKind } from '../types';
 16	import { useCustomTranslation } from '../useCustomTranslationHook';
 17	import {
 18	  LazyNameValueEditor,
 19	  NameValueEditorPair,
 20	} from '../utils/NameValueEditor';
 21	import { CommonModalProps, ModalBody, ModalFooter } from './Modal';
 22	
 23	type AnnotationsModalProps = {
 24	  titleKey: string;
 25	  errorMessage: string;
 26	  extraProps: {
 27	    resource: K8sResourceKind;
 28	    resourceModel: K8sKind;
 29	    cluster?: string;
 30	  };
 31	} & CommonModalProps;
 32	
 33	const ANNOTATIONS_PATH = '/metadata/annotations';
 34	
 35	export const AnnotationsModal: React.FC<AnnotationsModalProps> = ({
 36	  extraProps: { resource, resourceModel, cluster },
 37	  closeModal,
 38	  isOpen,
 39	}) => {
 40	  const [inProgress, setProgress] = React.useState(false);
 41	  const [tags, setTags] = React.useState(() =>
 42	    _.isEmpty(getAnnotations(resource))
 43	      ? [['', '']]
 44	      : _.toPairs(getAnnotations(resource))
 45	  );
 46	  const [errorMessage, setErrorMessage] = React.useState(null);
 47	
 48	  const { t } = useCustomTranslation();
 49	
 50	  const onSubmit = (e?: any) => {
 51	    setProgress(true);
 52	    if (e) {
 53	      e.preventDefault();
 54	    }
 55	    // We just throw away any rows where the key is blank
 56	    const usedTags = _.reject(tags, (tag) =>
 57	      _.isEmpty(tag[NameValueEditorPair.Name])
 58	    );
 59	
 60	    const keys = usedTags.map((tag) => tag[NameValueEditorPair.Name]);
 61	    if (_.uniq(keys).length !== keys.length) {
 62	      setErrorMessage(t('Duplicate keys found.'));
 63	      return;
 64	    }
 65	    const patch = [
 66	      {
 67	        path: ANNOTATIONS_PATH,
 68	        op: _.isEmpty(getAnnotations(resource)) ? 'add' : 'replace',
 69	        value: _.fromPairs(usedTags),
 70	      },
 71	    ];
 72	    k8sPatch({
 73	      model: resourceModel,
 74	      resource,
 75	      data: patch,
 76	      ...(!!cluster ? { cluster } : {}),
 77	    })
 78	      .then(() => {
 79	        closeModal();
 80	      })
 81	      .catch((err) => {
 82	        setErrorMessage(err.message);
 83	      })
 84	      .finally(() => {
 85	        setProgress(false);
 86	      });
 87	  };
 88	
 89	  const header = (
 90	    <Title headingLevel="h1" size={TitleSizes['2xl']}>
 91	      {t('Edit annotations')}
 92	    </Title>
 93	  );
 94	  return (
 95	    <Modal
 96	      isOpen={isOpen}
 97	      header={header}
 98	      variant={ModalVariant.small}
 99	      showClose={false}
100	    >
101	      <ModalBody className="modalBody">
102	        <LazyNameValueEditor
103	          nameValuePairs={tags}
104	          submit={onSubmit}
105	          updateParentData={({ nameValuePairs }) => {
106	            setTags(nameValuePairs);
107	          }}
108	        />
109	        <FormAlertInline
110	          title={t('An error occurred')}
111	          message={errorMessage}
112	        />
113	      </ModalBody>
114	      <ModalFooter>
115	        <Button
116	          key="cancel"
117	          variant="secondary"
118	          onClick={closeModal}
119	          isDisabled={inProgress}
120	        >
121	          {t('Cancel')}
122	        </Button>
123	        {!inProgress ? (
124	          <Button key="Save" variant="primary" onClick={onSubmit}>
125	            {t('Save')}
126	          </Button>
127	        ) : (
128	          <LoadingInline />
129	        )}
130	      </ModalFooter>
131	    </Modal>
132	  );
133	};
134	
135	export default AnnotationsModal;

